# scripts/lint_telemetry_schema.py
# Run as: python3 scripts/lint_telemetry_schema.py
import os, ast, yaml, sys
from pathlib import Path


def load_registry(schema_dir: str = "telemetry-schema/metrics") -> dict:
    """Returns {metric_name: schema_entry} from all YAML files."""
    registry = {}
    for path in Path(schema_dir).glob("*.yaml"):
        data = yaml.safe_load(open(path))
        for entry in data.get("metrics", []):
            registry[entry["name"]] = entry
    return registry


def extract_metric_names_from_source(src_dir: str = ".") -> set[str]:
    """Find all Counter/Gauge/Histogram/Summary constructor calls and extract their names."""
    found = set()
    for path in Path(src_dir).rglob("*.py"):
        try:
            tree = ast.parse(open(path).read())
        except SyntaxError:
            continue
        for node in ast.walk(tree):
            if isinstance(node, ast.Call):
                func = node.func
                if isinstance(func, ast.Name) and func.id in {"Counter", "Gauge", "Histogram", "Summary"}:
                    if node.args and isinstance(node.args[0], ast.Constant):
                        found.add(node.args[0].value)
    return found


def lint(schema_dir="telemetry-schema/metrics", src_dir=".") -> list[str]:
    registry = load_registry(schema_dir)
    emitted = extract_metric_names_from_source(src_dir)
    errors = []
    for name in emitted:
        if name not in registry:
            errors.append(f"UNREGISTERED metric: {name} — add it to the schema registry")
    for name, entry in registry.items():
        if entry.get("status") == "removed" and name in emitted:
            errors.append(f"REMOVED metric still emitted: {name} — remove the instrumentation")
    return errors


if __name__ == "__main__":
    errors = lint()
    if errors:
        for e in errors:
            print(f"ERROR: {e}")
        sys.exit(1)
    print("Schema lint passed")

# find_metric_consumers.py — find all references to a metric name across the observability repo
import re
import sys
from pathlib import Path


def find_consumers(metric_name: str, search_dirs: list[str]) -> dict[str, list[int]]:
    """Return {file_path: [line_numbers]} where metric_name appears."""
    pattern = re.compile(re.escape(metric_name))
    results: dict[str, list[int]] = {}
    for dir_ in search_dirs:
        for path in Path(dir_).rglob("*"):
            if path.suffix not in {".yaml", ".yml", ".json", ".py", ".md"}:
                continue
            try:
                lines = path.read_text().splitlines()
            except (UnicodeDecodeError, PermissionError):
                continue
            hits = [i + 1 for i, line in enumerate(lines) if pattern.search(line)]
            if hits:
                results[str(path)] = hits
    return results


if __name__ == "__main__":
    metric = sys.argv[1] if len(sys.argv) > 1 else "claude_api_request_latency_ms"
    consumers = find_consumers(metric, ["dashboards", "alerts", "runbooks", "."])
    if not consumers:
        print(f"No consumers found for {metric}")
    else:
        print(f"Consumers of {metric}:")
        for path, lines in consumers.items():
            print(f"  {path}: lines {lines}")
